from matplotlib import pyplot as pltimport cv2from skimage import io, img_as_ubytefrom cv2_rolling_ball import subtract_background_rolling_ballimg = cv2.imread("../data/Alloy_gradient.jpg", cv2.IMREAD_GRAYSCALE)# =============================================================================# # skimage reads RGB, OpenCV expects BGR# img_bgr = cv2.cvtColor(img, cv2.COLOR_RGB2BGR)## clahe = cv2.createCLAHE(clipLimit=3, tileGridSize=(8, 8))## lab = cv2.cvtColor(img_bgr, cv2.COLOR_BGR2LAB)## l, a, b = cv2.split(lab)## clahe_l = clahe.apply(l)## lab_clahe = cv2.merge((clahe_l, a, b))## bgr_clahe = cv2.cvtColor(lab_clahe, cv2.COLOR_LAB2BGR)# rgb_clahe = cv2.cvtColor(bgr_clahe, cv2.COLOR_BGR2RGB)## plt.imshow(rgb_clahe)# plt.axis("off")# plt.show()# =============================================================================radius = 30final_img, background = subtract_background_rolling_ball(    img,    radius,    light_background=True,    use_paraboloid=False,    do_presmooth=True)final_img = img_as_ubyte(final_img)clahe = cv2.createCLAHE(    clipLimit=3,    tileGridSize=(8, 8))clahe_img = clahe.apply(final_img)plt.imshow(clahe_img, cmap  ="grey")